  /** Chuẩn bị map thông tin phòng (chi tiết hiển thị) từ danh sách rate */
  private async buildRoomMap(aggregatedRates: AggregatedRateRow[]): Promise<Map<number, Room>> {
    const map = new Map<number, Room>();
    const roomIds = Array.from(new Set(aggregatedRates.map(r => r.roomId)));
    if (!roomIds.length) return map;

    const rooms = await this.roomRepo.searchRoomByIds(roomIds);
    rooms.forEach(r => {
      map.set(r.id, r);
    });
    return map;
  }

  /** Chuẩn bị map thông tin khách sạn (chi tiết hiển thị) từ danh sách hotelIds */
  private async buildHotelMap(_hotelIds: number[]): Promise<Map<number, Hotel>> {
    const map = new Map<number, Hotel>();
    const hotelIds = Array.from(new Set(_hotelIds.map(r => r)));
    if (!hotelIds.length) return map;

    const hotels = await this.hotelRepo.searchHotelByIds(hotelIds);
    hotels.forEach(h => {
      map.set(h.id, h);
    });
    return map;
  }

  private buildSurchargeCalendarMap(rows: SurchargeRateCalendarRow[]): SurchargeCalendarMap {
    const byRoomDate = new Map<string, SurchargeRateCalendarRow[]>();
    const byHotelDate = new Map<string, SurchargeRateCalendarRow[]>();

    rows.forEach(row => {
      const dateKey = dayjs(row.stayDate).format('YYYY-MM-DD');
      if (row.roomId) {
        const key = `${row.roomId}:${dateKey}`;
        const list = byRoomDate.get(key) ?? [];
        list.push(row);
        byRoomDate.set(key, list);
      } else {
        const key = `${row.hotelId}:${dateKey}`;
        const list = byHotelDate.get(key) ?? [];
        list.push(row);
        byHotelDate.set(key, list);
      }
    });

    return { byRoomDate, byHotelDate };
  }

